export type CircuitState = "closed" | "open" | "half-open";

interface CircuitRecord {
  state: CircuitState;
  failures: number;
  openedAt: number;
  halfOpenInFlight: number;
}

export type CircuitBreakerRegistry = Map<string, CircuitRecord>;

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

const DEFAULT_THRESHOLD = 5;
const DEFAULT_COOLDOWN = 30_000;
const DEFAULT_HALF_OPEN_MAX_REQUESTS = 1;
const DEFAULT_FAILURE_STATUS_CODES = [408, 409, 425, 429, 500, 502, 503, 504];

// Internal hidden key used to carry the circuit breaker registry from a
// parent `createFetch` instance to clients derived from it via `.create()`.
export const circuitBreakerRegistrySymbol: unique symbol = Symbol(
  "ofetch.circuitBreakerRegistry"
);

export function resolveCircuitBreakerOptions(
  option: true | CircuitBreakerOptions | undefined
): ResolvedCircuitBreakerOptions | undefined {
  if (!option) {
    return undefined;
  }
  const opts = option === true ? {} : option;
  return {
    threshold: opts.threshold ?? DEFAULT_THRESHOLD,
    cooldown: opts.cooldown ?? DEFAULT_COOLDOWN,
    halfOpenMaxRequests: opts.halfOpenMaxRequests ?? DEFAULT_HALF_OPEN_MAX_REQUESTS,
    failureStatusCodes: opts.failureStatusCodes ?? DEFAULT_FAILURE_STATUS_CODES,
  };
}

// Resolves the origin used to key circuit breaker state. Must be called with
// the effective request (post onRequest hooks and baseURL/query rewriting).
export function getRequestOrigin(request: FetchRequest): string | undefined {
  try {
    if (typeof request === "string") {
      return new URL(request).origin;
    }
    if (request instanceof URL) {
      return request.origin;
    }
    if (request instanceof Request) {
      return new URL(request.url).origin;
    }
  } catch {
    return undefined;
  }
  return undefined;
}

function getRecord(
  registry: CircuitBreakerRegistry,
  origin: string
): CircuitRecord {
  let record = registry.get(origin);
  if (!record) {
    record = { state: "closed", failures: 0, openedAt: 0, halfOpenInFlight: 0 };
    registry.set(origin, record);
  }
  return record;
}

export interface CircuitGateResult {
  allowed: boolean;
  isProbe: boolean;
}

// Checks (and possibly transitions open -> half-open) circuit state, and
// reserves a half-open probe slot when applicable. Must be called at most
// once per logical request (not per retry attempt).
export function checkCircuitGate(
  registry: CircuitBreakerRegistry,
  origin: string,
  options: ResolvedCircuitBreakerOptions,
  now: number
): CircuitGateResult {
  const record = getRecord(registry, origin);

  if (record.state === "open") {
    if (now - record.openedAt >= options.cooldown) {
      record.state = "half-open";
      record.halfOpenInFlight = 0;
    } else {
      return { allowed: false, isProbe: false };
    }
  }

  if (record.state === "half-open") {
    if (record.halfOpenInFlight >= options.halfOpenMaxRequests) {
      return { allowed: false, isProbe: false };
