    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it("does not apply circuit tracking when option is omitted", async () => {
    const fetchMock = vi.fn(async () => jsonResponse(500));
    const $fetch = createFetch({ fetch: fetchMock as unknown as Fetch });

    for (let i = 0; i < 20; i++) {
      await $fetch("https://api.example.com/x", { retry: false }).catch(
        () => {}
      );
    }

    // No circuit breaker configured -> every call reaches the underlying fetch.
    expect(fetchMock).toHaveBeenCalledTimes(20);
  });

  it("opens the circuit after `threshold` consecutive failures and fast-fails", async () => {
    const fetchMock = vi.fn(async () => jsonResponse(500));
    const $fetch = createFetch({ fetch: fetchMock as unknown as Fetch });

    for (let i = 0; i < 3; i++) {
      await expect(
        $fetch("https://api.example.com/x", {
          retry: false,
          circuitBreaker: { threshold: 3, cooldown: 30_000 },
        })
      ).rejects.toThrow();
    }
    expect(fetchMock).toHaveBeenCalledTimes(3);

    // Circuit is now open: next call must fast-fail without calling fetch.
    await expect(
      $fetch("https://api.example.com/x", {
        retry: false,
        circuitBreaker: { threshold: 3, cooldown: 30_000 },
      })
    ).rejects.toThrow(/Circuit breaker is open/);
    expect(fetchMock).toHaveBeenCalledTimes(3);
  });

  it("uses defaults when circuitBreaker: true is passed", async () => {
    const fetchMock = vi.fn(async () => jsonResponse(500));
    const $fetch = createFetch({ fetch: fetchMock as unknown as Fetch });

    for (let i = 0; i < 5; i++) {
      await expect(
        $fetch("https://api.example.com/x", {
          retry: false,
          circuitBreaker: true,
        })
      ).rejects.toThrow();
    }
    expect(fetchMock).toHaveBeenCalledTimes(5);

    await expect(
      $fetch("https://api.example.com/x", {
        retry: false,
        circuitBreaker: true,
      })
    ).rejects.toThrow(/Circuit breaker is open/);
    expect(fetchMock).toHaveBeenCalledTimes(5);
  });

  it("keys circuit state by origin, not path", async () => {
    const fetchMock = vi.fn(async () => jsonResponse(500));
    const $fetch = createFetch({ fetch: fetchMock as unknown as Fetch });
    const opts = {
      retry: false as const,
      circuitBreaker: { threshold: 2, cooldown: 30_000 },
    };

    await expect($fetch("https://api.example.com/a", opts)).rejects.toThrow();
    await expect($fetch("https://api.example.com/b", opts)).rejects.toThrow();
    expect(fetchMock).toHaveBeenCalledTimes(2);

    // Same origin, different path -> circuit is open.
    await expect(
      $fetch("https://api.example.com/c", opts)
    ).rejects.toThrow(/Circuit breaker is open/);
    expect(fetchMock).toHaveBeenCalledTimes(2);

    // Different origin -> unaffected.
    await expect(
      $fetch("https://other.example.com/a", opts)
    ).rejects.toThrow();
    expect(fetchMock).toHaveBeenCalledTimes(3);
  });

  it("resolves relative string requests via baseURL for origin keying", async () => {
    const fetchMock = vi.fn(async () => jsonResponse(500));
